import React, { useState, useRef } from 'react';

export default function FileDropzone() {
  const [files, setFiles] = useState([]);
  const [isDragActive, setIsDragActive] = useState(false);
  const fileInputRef = useRef(null);

  const processFiles = (uploadedFiles) => {
    Array.from(uploadedFiles).forEach(file => {
      if (file.size > 5 * 1024 * 1024) {
        alert(`File ${file.name} exceeds 5MB size limit.`);
        return;
      }

      const id = Date.now() + Math.random().toString(36).substring(2, 9);
      const newFile = { id, name: file.name, size: (file.size / 1024).toFixed(1) + " KB", progress: 0, status: "uploading" };
      setFiles(prev => [...prev, newFile]);

      // Mock progress simulation
      let prog = 0;
      const interval = setInterval(() => {
        prog += 20;
        setFiles(prev => prev.map(f => {
          if (f.id === id) {
            return { ...f, progress: prog, status: prog >= 100 ? "completed" : "uploading" };
          }
          return f;
        }));
        if (prog >= 100) clearInterval(interval);
      }, 300);
    });
  };

  const handleDrag = (e) => {
    e.preventDefault();
    if (e.type === "dragenter" || e.type === "dragover") {
      setIsDragActive(true);
    } else if (e.type === "dragleave") {
      setIsDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setIsDragActive(false);
    if (e.dataTransfer.files) {
      processFiles(e.dataTransfer.files);
    }
  };

  const removeFile = (id) => {
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  return (
    <div className="w-full max-w-md mx-auto py-10 font-sans">
      <div
        onDragEnter={handleDrag}
        onDragOver={handleDrag}
        onDragLeave={handleDrag}
        onDrop={handleDrop}
        onClick={() => fileInputRef.current.click()}
        className={`border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition focus:outline-none ${
          isDragActive ? 'border-purple-500 bg-purple-50/50' : 'border-gray-300 hover:border-purple-400 bg-white'
        }`}
      >
        <input ref={fileInputRef} type="file" multiple onChange={(e) => processFiles(e.target.files)} className="hidden" />
        <svg className="w-10 h-10 text-gray-400 mx-auto mb-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
        <p className="text-sm font-semibold text-gray-700">Drag & drop files or <span className="text-purple-600">browse</span></p>
        <p className="text-xs text-gray-400 mt-1">Image or PDF files up to 5MB</p>
      </div>

      {files.length > 0 && (
        <div className="mt-6 flex flex-col gap-3">
          {files.map(file => (
            <div key={file.id} className="border border-gray-100 rounded-lg p-3 bg-white shadow-xs flex items-center justify-between">
              <div className="flex-1 mr-4">
                <div className="flex justify-between text-xs font-semibold text-gray-700 mb-1">
                  <span className="truncate">{file.name}</span>
                  <span>{file.progress}%</span>
                </div>
                <div className="w-full bg-gray-100 h-1.5 rounded-full overflow-hidden">
                  <div className="bg-purple-500 h-full transition-all" style={{ width: `${file.progress}%` }} />
                </div>
              </div>
              <button onClick={() => removeFile(file.id)} className="text-gray-400 hover:text-red-500">
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
